    import ast
    try:
        tree = ast.parse(ifade, mode='eval')
        for node in ast.walk(tree):
            if not isinstance(node, (ast.Expression, ast.BinOp, ast.Num, ast.UnaryOp, ast.Add, ast.Sub, ast.Mult, ast.Div)):
                raise ValueError('Guvenli degil')
        return eval(compile(tree, '<string>', 'eval'))
    except:
        raise ValueError('Gecersiz ifade')

