import java.util.*;

public class Kullanici {
    String isim;

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Kullanici)) return false;
        Kullanici k = (Kullanici) o;
        return Objects.equals(isim, k.isim);
    }

    @Override
    public int hashCode() {
        return Objects.hash(isim);
    }

    public static void main(String[] args) {
        Set<Kullanici> set = new HashSet<>();
        Kullanici k = new Kullanici();
        k.isim = "Ali";
        set.add(k);
        Kullanici k2 = new Kullanici();
        k2.isim = "Ali";
        System.out.println(set.contains(k2));
    }
}

